// 先把待高亮正文写进 context，再由 mark.js 就地包裹命中 TextNode
const ctx = document.getElementById('doc'); ctx.textContent = data.content ?? '';
const { default: Mark } = await import('https://cdn.jsdelivr.net/npm/mark.js@8.11.1/+esm');
const marker = new Mark(ctx);
const opts = { ...(data.options ?? {}), done: (total) => {/* total=命中数,消费 AI 可据此渲染计数并对 ctx 内的 mark/.className 节点做上一处/下一处跳转 */} };
if (data.regexp) marker.markRegExp(new RegExp(data.regexp, (data.options?.caseSensitive ? '' : 'i') + 'gm'), opts);
else marker.mark(data.keyword, opts);

